public AccountSdfResp getAccountSdfInfo(long partnerId, int partnerType) throws TException {
    SdfAdAccount accountSdf = adAccountSdfAppService.getAccountSdfInfo(partnerId, partnerType);
    AccountSdfResp sdfResp = trans2SdfResp(accountSdf);
    return sdfResp;
}

@Override
public SdfSignInfoResp getSdfSignInfo(long partnerId, int partnerType) throws TException {
    SdfSignInfoResp resp = new SdfSignInfoResp();
    try {
        Pair<SdfAccountActivityInfo, SdfAdAccountSign> info = adAccountSdfAppService.getSdfSignInfo(partnerId, partnerType);
        SdfSignInfoDTO signInfoDTO = trans2SdfActivityResp(info.getLeft(), info.getRight());
        com.sankuai.meituan.waimai.bizad.billing.platform.vo.account.SdfRatioInfoDTO ratioInfo = adAccountSdfAppService.getRatioInfo(partnerId, partnerType, info.getRight());
        if (ratioInfo != null) {
            signInfoDTO.setRatioInfo(ratioInfo);
        }

        resp.setSdfSignInfoDTO(signInfoDTO);
        resp.setResult(new Result(true, 0, "success"));
    } catch (Exception e) {
        logger.error("AdAccountServiceImpl.getSdfSignInfo Exception. partnerId: {}, partnerType: {}", partnerId, partnerType, e);
        resp.setResult(new Result(false, 1, "系统异常"));
    }
    return resp;
}

@Override
public Result saveSdfSign(long partnerId, int partnerType) throws TException {
    return adAccountSdfAppService.saveSdfSign(partnerId, partnerType, SdfAdAccountSignOperateTypeEnum.SELF_SIGN.getType(), null);
}

@Override
public Result sdfSign(SdfSignReq req) throws TException {
    logger.info("AdAccountSdfAppService.sdfSign is start,partnerId:{} partnerType:{} activityId:{} operateType:{}", req.getPartnerId(), req.getPartnerType(), req.getActivityId(), req.getOperateType());
    SdfSignExtraInfo extraInfo = convertTodSdfSignExtraInfo(req.getExtraInfo());
    if (SdfAdAccountSignOperateTypeEnum.isSign(req.getOperateType())) {
        extraInfo.setRemark("商家自助签约");
        if (req.getCashRatio() != null && !req.getCashRatio().isEmpty()) {
            try {
                extraInfo.setCashRatio(new BigDecimal(req.getCashRatio()));
            } catch (NumberFormatException e) {
                return new Result(false, 1, "cashRatio格式非法: " + req.getCashRatio());
            }
        }
        return adAccountSdfAppService.saveSdfSign(req.getPartnerId(), req.getPartnerType(), req.getOperateType(), extraInfo);
    } else if (SdfAdAccountSignOperateTypeEnum.isTerminate(req.getOperateType())) {
        extraInfo.setRemark(req.getOperateType() == 2 ? "商家自助解约" : "解约");
        return adAccountSdfAppService.terminateSdfSign(req.getPartnerId(), req.getPartnerType(), req.getActivityId(), req.getOperateType(), extraInfo);
    }
    return new Result(false, 1, "不支持的操作类型");
}

@Override
public Result aiSignSdf(long partnerId, int partnerType) {
    SdfSignExtraInfo sdfSignExtraInfo = new SdfSignExtraInfo();
    sdfSignExtraInfo.setSignSourceCode(SdfSignSourceEnum.AI.getCode());
    sdfSignExtraInfo.setSignSourceName(SdfSignSourceEnum.AI.getDesc());
    sdfSignExtraInfo.setSignPartnerId(partnerId);
    sdfSignExtraInfo.setPlatform(4); // https://km.sankuai.com/collabpage/2729963893
    sdfSignExtraInfo.setAcctId(partnerId);
    sdfSignExtraInfo.setToken("ai-sign-sdf");
    sdfSignExtraInfo.setLaunchExtendInfo("ai-sign-sdf");

    return adAccountSdfAppService.aiSignSdf(partnerId, partnerType, SdfAdAccountSignOperateTypeEnum.AI_CALL_SIGN.getType(), sdfSignExtraInfo);
}

