package com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model;

import com.sankuai.meituan.waimai.bizad.billing.platform.vo.account.SdfSignExtraInfoDTO;

import java.math.BigDecimal;

public class SdfSignExtraInfo {
    private Long acctId;
    private String token;
    private Integer platform;
    private String ip;
    private String mis;
    private String remark;
    private String accountUserName;
    private Long planViewId;
    private int signSourceCode;
    private String signSourceName;
    private long signPartnerId;
    private int tryCount;
    private boolean signStatus;
    private String errorMsg;
    private String launchExtendInfo;

    /** 自定义模式下商家传入的现金比例，单位与 cashRatioDecimal 一致 */
    private BigDecimal cashRatio;

    public String getIp() {
        return ip;
    }

    public void setIp(String ip) {
        this.ip = ip;
    }

    public Long getAcctId() {
        return acctId;
    }

    public void setAcctId(Long acctId) {
        this.acctId = acctId;
    }

    public String getToken() {
        return token;
    }

    public void setToken(String token) {
        this.token = token;
    }

    public Integer getPlatform() {
        return platform;
    }

    public void setPlatform(Integer platform) {
        this.platform = platform;
    }

    public String getMis() {
        return mis;
    }

    public void setMis(String mis) {
        this.mis = mis;
    }

    public String getRemark() {
        return remark;
    }

    public void setRemark(String remark) {
        this.remark = remark;
    }

    public String getAccountUserName() {
        return accountUserName;
    }

    public void setAccountUserName(String accountUserName) {
        this.accountUserName = accountUserName;
    }

    public Long getPlanViewId() {
        return planViewId;
    }

    public void setPlanViewId(Long planViewId) {
        this.planViewId = planViewId;
    }

    public int getSignSourceCode() {
        return signSourceCode;
    }

    public void setSignSourceCode(int signSourceCode) {
        this.signSourceCode = signSourceCode;
    }

    public String getSignSourceName() {
        return signSourceName;
    }

    public void setSignSourceName(String signSourceName) {
        this.signSourceName = signSourceName;
    }

    public long getSignPartnerId() {
        return signPartnerId;
    }

    public void setSignPartnerId(long signPartnerId) {
        this.signPartnerId = signPartnerId;
    }

    public int getTryCount() {
        return tryCount;
    }

    public void setTryCount(int tryCount) {
        this.tryCount = tryCount;
    }

    public boolean isSignStatus() {
        return signStatus;
    }

