 * @Author zoufangfang
 * @Date 2023/12/25 3:07 PM
 */
public class SdfAccountActivityInfo {
    private long id;
    private String poiName;
    private long cashRatio;
    private long redRatio;
    private int startDate;
    private int endDate;
    private int cashCycleDate;
    @Deprecated
    private int redCycleDate;

    /**
     * 现金返还比例，用于替换原有cashRatio字段
     */
    private BigDecimal cashRatioDecimal = BigDecimal.ZERO;

    /**
