    private Integer ratioMode;
    /** 动态档位变量值 */
    private BigDecimal ratioVariable;

    public long getId() {
        return id;
    }

    public void setId(long id) {
        this.id = id;
    }

    public String getPoiName() {
        return poiName;
    }

    public void setPoiName(String poiName) {
        this.poiName = poiName;
    }

    public long getCashRatio() {
        return cashRatio;
    }

    public void setCashRatio(long cashRatio) {
        this.cashRatio = cashRatio;
    }

    public long getRedRatio() {
        return redRatio;
    }

    public void setRedRatio(long redRatio) {
        this.redRatio = redRatio;
    }

    public int getStartDate() {
        return startDate;
    }

    public void setStartDate(int startDate) {
        this.startDate = startDate;
    }

    public int getEndDate() {
        return endDate;
    }

    public void setEndDate(int endDate) {
        this.endDate = endDate;
    }

    public int getCashCycleDate() {
        return cashCycleDate;
    }

    public void setCashCycleDate(int cashCycleDate) {
        this.cashCycleDate = cashCycleDate;
    }

    public int getRedCycleDate() {
