package com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model;

import com.sankuai.meituan.waimai.bizad.billing.platform.vo.account.SdfSignExtraInfoDTO;
import org.junit.Test;

import static org.junit.Assert.*;

/**
 * @ClassName SdfSignExtraInfoConvertTest
 * @Description 测试 SdfSignExtraInfo.convertTodSdfSignExtraInfo 方法中
 *   signSourceCode 字段的透传逻辑（P0-2：sign HTTP 入参扩展）
 *
 * 对应需求：#94388352 随单返首页弹窗一键开启
 * 修改点：SdfSignExtraInfo.convertTodSdfSignExtraInfo 需补充 signSourceCode 透传
 *
 * 测试维度：
 *   TC01 - signSourceCode=3（C端弹窗）→ 转换后 signSourceCode=3
 *   TC02 - signSourceCode=0（DEFAULT，向前兼容）→ 转换后 signSourceCode=0
 *   TC03 - signSourceCode=1（AI）→ 转换后 signSourceCode=1
 *   TC04 - signSourceCode=2（AURORA_AGENT_OPERATION）→ 转换后 signSourceCode=2
 *   TC05 - signSourceCode=99（非法值，不校验直接透传）→ 转换后 signSourceCode=99
 *   TC06 - dto 为 null → 返回默认 SdfSignExtraInfo，signSourceCode=0（int 默认值）
 *   TC07 - 不设置 signSourceCode（未调用 setSignSourceCode）→ 转换后 signSourceCode=0
 * @Author ai-coding
 * @Date 2026-05-20
 */
public class SdfSignExtraInfoConvertTest {

    // ============================================================
    // TC01: signSourceCode=3（C端首页弹窗签约，本次新增枚举值）
    // ============================================================
    @Test
    public void tc01_signSourceCode3_cPopUpWindow_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(3);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=3 应透传", 3, result.getSignSourceCode());
    }

    // ============================================================
    // TC02: signSourceCode=0（DEFAULT，历史兼容）
    // ============================================================
    @Test
    public void tc02_signSourceCode0_default_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(0);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=0 应透传，与原行为兼容", 0, result.getSignSourceCode());
    }

    // ============================================================
    // TC03: signSourceCode=1（AI 外呼）
    // ============================================================
    @Test
    public void tc03_signSourceCode1_ai_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(1);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=1 应透传", 1, result.getSignSourceCode());
    }

    // ============================================================
    // TC04: signSourceCode=2（欧若拉代运营）
    // ============================================================
    @Test
    public void tc04_signSourceCode2_auroraAgentOperation_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(2);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=2 应透传", 2, result.getSignSourceCode());
    }

    // ============================================================
    // TC05: signSourceCode=99（非法值，不校验，直接透传）
    // ============================================================
    @Test
    public void tc05_illegalSignSourceCode_passedThroughWithoutValidation() {
        SdfSignExtraInfoDTO dto = buildDto(99);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("非法 signSourceCode=99 应不校验直接透传", 99, result.getSignSourceCode());
    }

    // ============================================================
    // TC06: dto 为 null → 返回默认对象，signSourceCode=0
    // ============================================================
    @Test
    public void tc06_dtNull_returnsDefaultExtraInfo_signSourceCodeIsZero() {
        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(null);

        assertNotNull("dto=null 时应返回默认 SdfSignExtraInfo 而非 null", result);
        assertEquals("dto=null 时 signSourceCode 应为 int 默认值 0", 0, result.getSignSourceCode());
    }

    // ============================================================
    // TC07: 不设置 signSourceCode（int optional 默认值为 0）
    // ============================================================
    @Test
    public void tc07_signSourceCodeNotSet_defaultZeroPassedThrough() {
        // Thrift generated DTO: optional i32 signSourceCode，未 set 时为 0
        SdfSignExtraInfoDTO dto = new SdfSignExtraInfoDTO();
        // 不调用 setSignSourceCode，保持 Thrift optional int 默认值 0

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("未设置 signSourceCode 时应为 0（透传 Thrift optional int 默认值）",
                0, result.getSignSourceCode());
    }

    // ============================================================
    // Helper
    // ============================================================
    private SdfSignExtraInfoDTO buildDto(int signSourceCode) {
        SdfSignExtraInfoDTO dto = new SdfSignExtraInfoDTO();
        dto.setSignSourceCode(signSourceCode);
        dto.setIp("127.0.0.1");
        dto.setMisId("test_mis");
        dto.setRemark("unit test");
        return dto;
    }
}

