package com.sankuai.meituan.waimai.bizad.billing.platform.domain.sdf;

/**
 * 随单返签约来源
 */
public enum SdfSignSourceEnum {

    DEFAULT(0, "默认签约来源"),
    AI(1, "AI外呼签约"),
    AURORA_AGENT_OPERATION(2, "欧若拉代运营工作台签约");

    private final int code;
    private final String desc;

    SdfSignSourceEnum(int code, String desc) {
        this.code = code;
        this.desc = desc;
    }

    public int getCode() {
        return code;
    }

    public String getDesc() {
        return desc;
    }

    public static SdfSignSourceEnum getEnumByCode(int code) {
        for (SdfSignSourceEnum value : SdfSignSourceEnum.values()) {
            if (value.getCode() == code) {
                return value;
            }
        }
        return null;
    }
}

