public Object sign(HttpServletRequest request) {
    long wmPoiId = GetParameterUtil.getWmPoiId(request);
    long activityId = GetParameterUtil.getLongParam(request, "activityId");
    String cashRatio = GetParameterUtil.getStrParam(request, "cashRatio");
    try {
        SdfSignExtraInfoDTO extraInfoDTO = new SdfSignExtraInfoDTO();
        extraInfoDTO.setAcctId(GetParameterUtil.getLongParam(request, Constants.ACCT_ID));
        extraInfoDTO.setIp(GetParameterUtil.getRealIp(request));
        extraInfoDTO.setPlatform(GetParameterUtil.getIntParam(request, Constants.PLAT_FORM));
        extraInfoDTO.setToken(GetParameterUtil.getStrParam(request, Constants.TOKEN));

        Result result = wmAdBillingMoneyProxy.sdfSignWithRatio(wmPoiId, PartnerType.POI.getIntValue(), activityId, 1002, extraInfoDTO, cashRatio);
        return MiscUtils.getReturnMessage(result.isSuccess() ? 0 : 1,
                result.isSuccess() ? "OK" : result.getMessage(), null);
    } catch (Exception e) {
        log.error("AdPoiSdfController sign partnerId orderback sign error,partnerId:{} activityId:{}", wmPoiId, activityId, e);
        return MiscUtils.getReturnMessage(CODE_ERROR, ERROR, "系统出问题啦，请联系管理员");
    }
}

