package com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model;

import com.sankuai.meituan.waimai.bizad.billing.platform.vo.account.SdfSignExtraInfoDTO;
import org.junit.Test;

import static org.junit.Assert.*;

/**
 * @ClassName SdfSignExtraInfoConvertTest
 * @Description 测试 SdfSignExtraInfo.convertTodSdfSignExtraInfo 方法中
 *   signSourceCode 字段的透传逻辑（P0-2：sign HTTP 入参扩展）
 *
 * 对应需求：#94388352 随单返首页弹窗一键开启
 * 修改点：SdfSignExtraInfo.convertTodSdfSignExtraInfo 需补充 signSourceCode 透传
 *
 * 测试维度：
 *   TC01 - signSourceCode=3（C端弹窗）→ 转换后 signSourceCode=3
 *   TC02 - signSourceCode=0（DEFAULT，向前兼容）→ 转换后 signSourceCode=0
 *   TC03 - signSourceCode=1（AI）→ 转换后 signSourceCode=1
 *   TC04 - signSourceCode=2（AURORA_AGENT_OPERATION）→ 转换后 signSourceCode=2
 *   TC05 - signSourceCode=99（非法值，不校验直接透传）→ 转换后 signSourceCode=99
 *   TC06 - dto 为 null → 返回默认 SdfSignExtraInfo，signSourceCode=0（int 默认值）
 *   TC07 - 不设置 signSourceCode（未调用 setSignSourceCode）→ 转换后 signSourceCode=0
 * @Author ai-coding
 * @Date 2026-05-20
 */
public class SdfSignExtraInfoConvertTest {

    // ============================================================
    // TC01: signSourceCode=3（C端首页弹窗签约，本次新增枚举值）
    // ============================================================
    @Test
    public void tc01_signSourceCode3_cPopUpWindow_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(3);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=3 应透传", 3, result.getSignSourceCode());
    }

    // ============================================================
    // TC02: signSourceCode=0（DEFAULT，历史兼容）
    // ============================================================
    @Test
    public void tc02_signSourceCode0_default_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(0);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=0 应透传，与原行为兼容", 0, result.getSignSourceCode());
    }

    // ============================================================
    // TC03: signSourceCode=1（AI 外呼）
    // ============================================================
    @Test
    public void tc03_signSourceCode1_ai_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(1);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=1 应透传", 1, result.getSignSourceCode());
    }

    // ============================================================
    // TC04: signSourceCode=2（欧若拉代运营）
    // ============================================================
    @Test
    public void tc04_signSourceCode2_auroraAgentOperation_passedThrough() {
        SdfSignExtraInfoDTO dto = buildDto(2);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("signSourceCode=2 应透传", 2, result.getSignSourceCode());
    }

    // ============================================================
    // TC05: signSourceCode=99（非法值，不校验，直接透传）
    // ============================================================
    @Test
    public void tc05_illegalSignSourceCode_passedThroughWithoutValidation() {
        SdfSignExtraInfoDTO dto = buildDto(99);

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("非法 signSourceCode=99 应不校验直接透传", 99, result.getSignSourceCode());
    }

    // ============================================================
    // TC06: dto 为 null → 返回默认对象，signSourceCode=0
    // ============================================================
    @Test
    public void tc06_dtNull_returnsDefaultExtraInfo_signSourceCodeIsZero() {
        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(null);

        assertNotNull("dto=null 时应返回默认 SdfSignExtraInfo 而非 null", result);
        assertEquals("dto=null 时 signSourceCode 应为 int 默认值 0", 0, result.getSignSourceCode());
    }

    // ============================================================
    // TC07: 不设置 signSourceCode（int optional 默认值为 0）
    // ============================================================
    @Test
    public void tc07_signSourceCodeNotSet_defaultZeroPassedThrough() {
        // Thrift generated DTO: optional i32 signSourceCode，未 set 时为 0
        SdfSignExtraInfoDTO dto = new SdfSignExtraInfoDTO();
        // 不调用 setSignSourceCode，保持 Thrift optional int 默认值 0

        SdfSignExtraInfo result = SdfSignExtraInfo.convertTodSdfSignExtraInfo(dto);

        assertNotNull(result);
        assertEquals("未设置 signSourceCode 时应为 0（透传 Thrift optional int 默认值）",
                0, result.getSignSourceCode());
    }

    // ============================================================
    // Helper
    // ============================================================
    private SdfSignExtraInfoDTO buildDto(int signSourceCode) {
        SdfSignExtraInfoDTO dto = new SdfSignExtraInfoDTO();
        dto.setSignSourceCode(signSourceCode);
        dto.setIp("127.0.0.1");
        dto.setMisId("test_mis");
        dto.setRemark("unit test");
        return dto;
    }
}

package com.sankuai.meituan.waimai.bizad.platform.billing.application.sdf;

import com.sankuai.meituan.util.ConfigUtilAdapter;
import com.sankuai.meituan.waimai.bizad.billing.platform.domain.sdf.SdfRatioModeEnum;
import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model.SdfAccountActivityInfo;
import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model.SdfAdAccountSign;
import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model.SdfBenefitRule;
import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model.SdfRedPackStage;
import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.repository.SdfRatioConfigFutureRepository;
import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.service.AdAccountSdfService;
import org.junit.After;
import org.junit.Before;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.MockedStatic;
import org.mockito.Mockito;
import org.mockito.junit.MockitoJUnitRunner;
import org.springframework.test.util.ReflectionTestUtils;

import java.math.BigDecimal;
import java.util.Arrays;
import java.util.Collections;

import static org.junit.Assert.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

/**
 * @ClassName GetSdfSignInfoPopupParamsTest
 * @Description 测试 getSdfSignInfo 接口中新增的3个弹窗参数字段计算逻辑：
 *   - redPacketIssueDays（红包发放总天数）
 *   - redPacketInflationRate（红包膨胀系数）
 *   - transferInRatio（转入比例）
 *
 * 对应需求：#94388352 随单返首页弹窗一键开启
 * 接口：AdAccountServiceImpl#getSdfSignInfo (RPC)
 *
 * 测试维度：
 *   TC01 - 有活动，有 benefitRule stage → redPacketIssueDays = max(endOffsetDays) 字符串
 *   TC02 - 有活动，benefitRule 为 null → redPacketIssueDays = null
 *   TC03 - 有活动，stage 列表为空 → redPacketIssueDays = null
 *   TC04 - 有活动，cashRatioDecimal 正常 → redPacketInflationRate = (red+cash)/cash 保留2位小数
 *   TC05 - 有活动，cashRatioDecimal = 0 → redPacketInflationRate = null（避免除零）
 *   TC06 - FIXED 模式 → transferInRatio = "30%"
 *   TC07 - CUSTOM 模式 → transferInRatio = "30%"（与 FIXED 相同，用 cashRatioDecimal 基础值）
 *   TC08 - DYNAMIC 模式 → transferInRatio = "5%~8%"（cashRatioDecimal ~ cashRatioDecimal+ratioVariable）
 *   TC09 - 无活动（activityInfo = null）→ 三个字段均不设置（为 null）
 * @Author ai-coding
 * @Date 2026-05-20
 */
@RunWith(MockitoJUnitRunner.class)
public class GetSdfSignInfoPopupParamsTest {

    @InjectMocks
    private AdAccountSdfAppService adAccountSdfAppService;

    @Mock
    private AdAccountSdfService adAccountSdfService;

    @Mock
    private SdfRatioConfigFutureRepository sdfRatioConfigFutureRepository;

    private MockedStatic<ConfigUtilAdapter> mockedConfigUtil;

    private static final long PARTNER_ID = 8001L;
    private static final int PARTNER_TYPE = 1;
    private static final long ACTIVITY_ID = 500L;

    @Before
    public void setUp() {
        ReflectionTestUtils.setField(adAccountSdfAppService, "self", adAccountSdfAppService);
        mockedConfigUtil = Mockito.mockStatic(ConfigUtilAdapter.class);
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getInt(anyString(), anyInt())).thenReturn(2);
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getInt(anyString())).thenReturn(2);
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getString(eq("sdf_ratio_max_cash"), anyString())).thenReturn("50");
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getString(anyString(), anyString()))
                .thenAnswer(inv -> inv.getArgument(1));
    }

    @After
    public void tearDown() {
        if (mockedConfigUtil != null) {
            mockedConfigUtil.close();
        }
    }

    // ============================================================
    // Helpers
    // ============================================================

    private SdfAccountActivityInfo buildActivityInfo(Integer ratioMode,
                                                      BigDecimal cashRatioDecimal,
                                                      BigDecimal redRatioDecimal,
                                                      BigDecimal ratioVariable,
                                                      SdfBenefitRule benefitRule) {
        SdfAccountActivityInfo info = new SdfAccountActivityInfo();
        info.setActivityId(ACTIVITY_ID);
        info.setPartnerId(PARTNER_ID);
        info.setPartnerType(PARTNER_TYPE);
        info.setRatioMode(ratioMode);
        info.setCashRatioDecimal(cashRatioDecimal);
        info.setRedRatioDecimal(redRatioDecimal);
        info.setRatioVariable(ratioVariable);
        info.setBenefitRule(benefitRule);
        info.setStartDate(20260101);
        info.setEndDate(20991231);
        return info;
    }

    private SdfBenefitRule buildBenefitRuleWithStages(int... endOffsetDaysArr) {
        SdfBenefitRule rule = new SdfBenefitRule();
        java.util.List<SdfRedPackStage> stages = new java.util.ArrayList<>();
        for (int i = 0; i < endOffsetDaysArr.length; i++) {
            SdfRedPackStage stage = new SdfRedPackStage();
            stage.setStartOffsetDays(i * 10);
            stage.setEndOffsetDays(endOffsetDaysArr[i]);
            stage.setRatio(new BigDecimal("0.05"));
            stages.add(stage);
        }
        rule.setSdfRedPackStageRules(stages);
        return rule;
    }

    // ============================================================
    // TC01: 有活动 + 有 benefitRule stage → redPacketIssueDays = max(endOffsetDays)
    // ============================================================
    @Test
    public void tc01_withActivity_benefitRuleHasStages_redPacketIssueDaysEqualsMaxEndOffset() {
        // stages: endOffsetDays = 10, 20, 30 → max = 30
        SdfBenefitRule rule = buildBenefitRuleWithStages(10, 20, 30);
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                null,
                rule);

        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);

        assertNotNull("redPacketIssueDays 应非 null", result);
        assertEquals("redPacketIssueDays 应等于 stages 中最大 endOffsetDays", "30", result);
    }

    // ============================================================
    // TC02: 有活动，benefitRule = null → redPacketIssueDays = null
    // ============================================================
    @Test
    public void tc02_withActivity_benefitRuleNull_redPacketIssueDaysIsNull() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                null,
                null);

        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);

        assertNull("benefitRule 为 null 时 redPacketIssueDays 应为 null", result);
    }

    // ============================================================
    // TC03: 有活动，stage 列表为空 → redPacketIssueDays = null
    // ============================================================
    @Test
    public void tc03_withActivity_stagesEmpty_redPacketIssueDaysIsNull() {
        SdfBenefitRule rule = new SdfBenefitRule();
        rule.setSdfRedPackStageRules(Collections.emptyList());
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                null,
                rule);

        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);

        assertNull("stage 列表为空时 redPacketIssueDays 应为 null", result);
    }

    // ============================================================
    // TC04: 正常 cashRatioDecimal → redPacketInflationRate = (red+cash)/cash 保留2位小数
    //   cashRatioDecimal=5, redRatioDecimal=2 → (5+2)/5 = 1.40
    // ============================================================
    @Test
    public void tc04_normalRatios_inflationRateCalculatedCorrectly() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                null,
                null);

        String result = adAccountSdfAppService.calcInflationRate(activityInfo);

        assertNotNull("redPacketInflationRate 应非 null", result);
        assertEquals("(5+2)/5 = 1.40", "1.40", result);
    }

    // ============================================================
    // TC05: cashRatioDecimal = 0 → redPacketInflationRate = null（避免除零）
    // ============================================================
    @Test
    public void tc05_cashRatioZero_inflationRateIsNull() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                BigDecimal.ZERO,
                new BigDecimal("2"),
                null,
                null);

        String result = adAccountSdfAppService.calcInflationRate(activityInfo);

        assertNull("cashRatioDecimal=0 时应返回 null 避免除零", result);
    }

    // ============================================================
    // TC06: FIXED 模式 → transferInRatio = "30%"
    // ============================================================
    @Test
    public void tc06_fixedMode_transferInRatioIsCashRatioWithPercent() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("30"),
                new BigDecimal("10"),
                null,
                null);

        String result = adAccountSdfAppService.calcTransferInRatio(activityInfo);

        assertNotNull(result);
        assertEquals("FIXED 模式 transferInRatio 应为 cashRatioDecimal + %", "30%", result);
    }

    // ============================================================
    // TC07: CUSTOM 模式 → transferInRatio = "30%"（与 FIXED 相同，用 cashRatioDecimal）
    // ============================================================
    @Test
    public void tc07_customMode_transferInRatioIsCashRatioWithPercent() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.CUSTOM.getMode(),
                new BigDecimal("30"),
                new BigDecimal("10"),
                new BigDecimal("1"),
                null);

        String result = adAccountSdfAppService.calcTransferInRatio(activityInfo);

        assertNotNull(result);
        assertEquals("CUSTOM 模式 transferInRatio 应为 cashRatioDecimal + %", "30%", result);
    }

    // ============================================================
    // TC08: DYNAMIC 模式 → transferInRatio = "cashRatioDecimal%~(cashRatioDecimal+ratioVariable)%"
    //   cashRatioDecimal=5, ratioVariable=3 → "5%~8%"
    // ============================================================
    @Test
    public void tc08_dynamicMode_transferInRatioIsRange() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.DYNAMIC.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                new BigDecimal("3"),
                null);

        String result = adAccountSdfAppService.calcTransferInRatio(activityInfo);

        assertNotNull(result);
        assertEquals("DYNAMIC 模式 transferInRatio 应为区间 cashRatioDecimal%~(cash+variable)%",
                "5%~8%", result);
    }

    // ============================================================
    // TC09: DYNAMIC 模式，ratioVariable 为 null → transferInRatio = "5%~5%" (变量视为0)
    // ============================================================
    @Test
    public void tc09_dynamicMode_ratioVariableNull_rangeEndsAtSameValue() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.DYNAMIC.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                null,  // ratioVariable = null
                null);

        String result = adAccountSdfAppService.calcTransferInRatio(activityInfo);

        assertNotNull(result);
        // ratioVariable is null → treated as 0 → "5%~5%"
        assertEquals("DYNAMIC 模式 ratioVariable=null 时上限等于下限", "5%~5%", result);
    }

    // ============================================================
    // TC10: 小数 cashRatioDecimal 的百分号格式（去尾零）
    //   cashRatioDecimal=29.5 → "29.5%"
    // ============================================================
    @Test
    public void tc10_decimalCashRatio_trailingZeroStripped() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("29.5"),
                new BigDecimal("10"),
                null,
                null);

        String result = adAccountSdfAppService.calcTransferInRatio(activityInfo);

        assertNotNull(result);
        assertEquals("小数比例应去尾零后加 %", "29.5%", result);
    }

    // ============================================================
    // TC11: 多 stage，验证取最大 endOffsetDays（stage 乱序）
    // ============================================================
    @Test
    public void tc11_stagesOutOfOrder_maxEndOffsetDaysTaken() {
        SdfBenefitRule rule = buildBenefitRuleWithStages(30, 10, 20);
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("5"),
                new BigDecimal("2"),
                null,
                rule);

        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);

        assertEquals("stage 乱序时也应取最大 endOffsetDays", "30", result);
    }

    // ============================================================
    // TC12: 精确 2位小数，膨胀系数结果为整数时仍补齐2位
    //   cashRatioDecimal=2, redRatioDecimal=2 → (2+2)/2 = 2.00
    // ============================================================
    @Test
    public void tc12_inflationRateIntegerResult_formattedWith2DecimalPlaces() {
        SdfAccountActivityInfo activityInfo = buildActivityInfo(
                SdfRatioModeEnum.FIXED.getMode(),
                new BigDecimal("2"),
                new BigDecimal("2"),
                null,
                null);

        String result = adAccountSdfAppService.calcInflationRate(activityInfo);

        assertNotNull(result);
        assertEquals("膨胀系数为整数时应保留 2 位小数", "2.00", result);
    }
}
